solutions.python:
class Trie:
    def __init__(self):
        self.children = [None]*26

    def insert(self, word):
        root = self
        for c in word:
            if root.children[ord(c) - ord('a')] is None:
                root.children[ord(c) - ord('a')] = Trie()
            root = root.children[ord(c) - ord('a')]

class Solution:
    def insert(self, root, words):
        trie = Trie()
        for word in words:
            trie.insert(word)

