class Trie {
    public:
        TrieNode* children[26];

        Trie() {
            for (int i = 0; i < 26; i++) {
                children[i] = nullptr;
            }
        }

        void insert(string word) {
            TrieNode* root = this;
            for (char c : word) {
                if (root->children[c - 'a'] == nullptr) {
                    root->children[c - 'a'] = new TrieNode();
                }
                root = root->children[c - 'a'];
            }
        }

};

void Solution::insert(Trie* root, vector<string>& words) {
    Trie trie;
    for (const string& word : words) {
        trie.insert(word);
    }
}
